//! This crate defines functions for converting between Rust types and a binary
//! encoding (`[u8]`) in the Mojom format.
//!
//! TODO(crbug.com/496920846): Link to the wire format spec when it's committed
//! to the tree.
//!
//! In order to be converted, a type must implement the `MojomParse` trait. This
//! trait is automatically implemented for types which are generated by the
//! Mojom bindings, as well as certain primitive types. The trait can be derived
//! for structs and enums (though enums which carry no data in their variants
//! should derive `PrimitiveEnum` instead, which automatically includes
//! `MojomParse`).
//!
//! This crate should generally not be directly depended on by users; instead,
//! use the higher-level binding APIs in `//mojo/public/rust/bindings`.

chromium::import! {
    "//mojo/public/rust/mojom_value_parser:mojom_value_parser_core";
    "//mojo/public/rust/mojom_value_parser:parsing_attribute";
}

pub use mojom_value_parser_core::{deserialize, deserialize_exact, serialize, ParsingResult};
pub use mojom_value_parser_core::{
    MessageHeader, MessageHeaderV1, MessageHeaderV2, MessageHeaderV3,
};
pub use mojom_value_parser_core::{MojomParse, PrimitiveEnum};
pub use parsing_attribute::{MojomParse, PrimitiveEnum};
